VALUES
  ('optometrist-moex-00374', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '進行裂孔板（stenopaeicslit）驗光時，若將裂孔放在160度時，以+1.00DS度數矯正可以得到最佳視力， 將裂孔轉至×70度時，以-3.00DS度數×得到最佳視力，則該受測×者的矯正度數為何？ ×', '["+1.00DS/-4.00DC 160", "+1.00DS/-3.00DC 160", "-3.00DS/+1.00DC 070", "-3.00DS/+4.00DC 160"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00375', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '利用自覺式鐘面圖（×clockdialtest）確認散光軸的敘述，下列何者最適×當？', '["受試者回覆1點和×7點鐘最黑，設定軸位為（1+7）/2=4點鐘相對的×10點方向，即120度", "受試者回覆3點和9點鐘最黑，設定軸位為180度", "受試者回覆1點和7點鐘最黑，設定軸位為160度", "受試者回覆1點和7點鐘與2點和8點鐘一樣黑，綜合驗光儀設定軸為45度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00376', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一位 60 歲的男性病人數年前視力檢查都正常，近期眼睛沒有受傷，也沒有接受眼科的手術。今日視力檢 查雙眼裸視只有0.3/0.3，戴上自己的眼鏡測視力，可以進步到0.6/0.7。最後在眼鏡前加上針孔（pinhole） 鏡片，視力可以再進步到1.0/1.0。此位病人最有可能的疾病為何？', '["白內障", "黃斑部病變", "青光眼", "屈光不正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00377', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有散光的受檢者，為何在進行裂孔板驗光（stenopaic slit refraction）步驟時，需要在找尋第一主要子午線', '["才能讓第一主要子午線對應到負散軸（minus cylinderaxis）", "才能讓第一主要子午線對應到正散軸（pluscylinderaxis）", "才能讓第一主要子午線對 應到最負的矯正度數", "才能讓第一主要子午線對應到最正的矯正度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00378', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者不是在自覺式驗光時可以達到雙眼視覺（binocularity）的方法？', '["Humphriss心理性中隔法（HumphrissPsychologicalSeptum）", "Turville鏡像法（Turvillemirrortechnique）", "Morgan投射中隔法（Morganprojectedseptummethod）", "矢量圖卡（VectographicCards）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00379', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於傑克森交叉圓柱鏡檢查法（Jackson’scross-cylinderlenstest），下列何者最不適當？', '["一般而言，我們會先找出柱面鏡軸度（cylinderaxis）而非柱面鏡度數（cylinderpower）", "通常我們會告訴病人交叉圓柱鏡的兩個情況可能都是模糊的，但是請病人告訴我們那個比較清晰或比較 不模糊", "每一種情況停留1秒鐘觀察", "若病人覺得兩個情況不一樣清楚，一般而言我們會往能提供給病人比較清楚的情況下，朝負圓柱鏡軸的 方向轉，以確定軸度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00380', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關針孔檢查（pinholetest），下列何者錯誤？', '["針孔可增加焦深（depthoffocus）", "針孔可縮小視網膜上的模糊環（retinalblurcirclesize）", "常用的針孔大小為2.5毫米（mm）或以上", "此檢查屬於自覺式驗光"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00381', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '使用綜合驗光儀上的傑克森交叉圓柱鏡（Jackson’scross-cylinderlens）測量+2.50DS/-1.25DC 090的散光 軸檢測時：', '["將傑克森交叉圓柱鏡上的「A」對齊在090位置 ×", "將傑克森交叉圓柱鏡上的紅點「P」對齊在090位置", "將傑克森交叉圓柱鏡上的「A」與紅點「P」中間點對齊在090位置", "將傑克森交叉圓柱鏡上的白點「P」對齊在090位置"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00382', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '對於老花眼患者，融像性交叉圓柱鏡（fusedcrosscylinder,FCC）檢查提供下列何種資訊？', '["準確的近距離度數", "暫時近距離的加入度", "近距離的調節幅度", "眼睛的散光度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
